1	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
2	const CURSED_SURCHARGE_RATE = 0.5;
3	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
4	const PROCESSING_FEE = 5;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  potion: 40,
9	  amulet: 60,
10	};
11	
12	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
13	
14	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
15	
16	const sumSurcharge = (items: Item[], appliesTo: (item: Item) => boolean, rate: number): number =>
17	  items.reduce((sum, item) => sum + (appliesTo(item) ? itemBasePremium(item) * rate : 0), 0);
18	
19	export function quote(customer: { yearsWithMHPCO: number }, items: Item[], contractIndex: number): number {
20	  const basePremium = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
21	  const cursedSurcharge = sumSurcharge(items, (item) => item.cursed, CURSED_SURCHARGE_RATE);
22	  const enchantmentSurcharge = sumSurcharge(items, (item) => item.enchantment >= 5, HIGH_ENCHANTMENT_SURCHARGE_RATE);
23	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
24	  return basePremium + cursedSurcharge + enchantmentSurcharge + firstInsuranceSurcharge + PROCESSING_FEE;
25	}
